class MetadataBuilder:
    @staticmethod
    def build_from_http_headers(headers: Dict[str, str], include_prefixes: Optional[List[str]] = None) -> List[Tuple[str, str]]:
        if include_prefixes is None:
            include_prefixes = ['x-', 'authorization', 'user-agent', 'accept', 'content-type']
        
        metadata = []
        for key, value in headers.items():
            key_lower = key.lower()
            if any(key_lower.startswith(prefix) for prefix in include_prefixes):
                metadata.append((key_lower, value))
        
        return metadata
    
    @staticmethod
    def build_from_user_input(user_metadata: Dict[str, str]) -> List[Tuple[str, str]]:
        return [(k.lower(), v) for k, v in user_metadata.items()]
    
    @staticmethod
    def merge_metadata(*metadata_lists: List[Tuple[str, str]]) -> List[Tuple[str, str]]:
        merged = {}
        for metadata_list in metadata_lists:
            for key, value in metadata_list:
                merged[key] = value
        return list(merged.items())


